  KEY `idx_contract_status` (`contract_status`),
  KEY `idx_expire_date` (`expire_date`),
  KEY `idx_sign_date` (`sign_date`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_person_in_charge_id` (`person_in_charge_id`)
) ENGINE=InnoDB AUTO_INCREMENT=33 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='合同信息表';
