DROP TABLE IF EXISTS `biz_customer`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `biz_customer` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `name` varchar(100) NOT NULL COMMENT '客户名称',
  `address` varchar(255) DEFAULT NULL COMMENT '客户地址',
  `province` varchar(50) DEFAULT NULL COMMENT '省份',
  `city` varchar(50) DEFAULT NULL COMMENT '城市',
  `district` varchar(50) DEFAULT NULL COMMENT '区/县',
  `detail_address` varchar(255) DEFAULT NULL COMMENT '详细地址（街道、门牌号等）',
  `region` varchar(50) DEFAULT NULL COMMENT '所属区域',
  `contact_person` varchar(50) DEFAULT NULL COMMENT '联系人',
  `contact_phone` varchar(20) DEFAULT NULL COMMENT '联系电话',
  `business_category` varchar(50) DEFAULT NULL COMMENT '业务类型一级分类: 加气站类/商业用气/工业用气',
  `business_type` varchar(50) DEFAULT NULL COMMENT '业务类型二级分类: CNG加气站/LPG加气站/餐饮类/团餐类/其他商业类/大型/中型/小型',
  `cooperation_category` varchar(50) DEFAULT '潜在客户' COMMENT '合作状态一级分类: 已合作/潜在/意向',
  `cooperation_status` varchar(50) DEFAULT '中潜力' COMMENT '合作状态二级分类: 正常履约/逾期客户/暂停合作/终止合作/高潜力/中潜力/低潜力/意向跟进',
  `gas_scale` varchar(50) DEFAULT NULL COMMENT '用气规模（工业客户辅助分类: 大型/中型/小型）',
  `smart_gas_system` varchar(255) DEFAULT NULL COMMENT '智慧燃气系统型号/部署情况',
  `maintenance_category` varchar(50) DEFAULT NULL COMMENT '运维需求分类: 高频报修/常规运维/无报修',
  `contract_info` varchar(500) DEFAULT NULL COMMENT '合同信息摘要',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `contract_expire_date` date DEFAULT NULL COMMENT '合同到期时间',
  `is_invalid` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否无效: 0-正常, 1-无效（多次对接无回应、无需求或不符合服务范围）',
  `tenant_id` bigint NOT NULL COMMENT '租户ID，数据隔离',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '逻辑删除: 0-未删除, 1-已删除',
  `follow_up_person_id` bigint DEFAULT NULL COMMENT '当前跟进人ID',
  `follow_up_person` varchar(50) DEFAULT NULL COMMENT '当前跟进人姓名',
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_business_category` (`business_category`),
  KEY `idx_business_type` (`business_type`),
  KEY `idx_cooperation_category` (`cooperation_category`),
  KEY `idx_cooperation_status` (`cooperation_status`),
  KEY `idx_region` (`region`),
  KEY `idx_contract_expire_date` (`contract_expire_date`),
  KEY `idx_maintenance_category` (`maintenance_category`)
) ENGINE=InnoDB AUTO_INCREMENT=38 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='客户信息表';
/*!40101 SET character_set_client = @saved_cs_client */;

